ee:message.ee:set-payload:
#[
%dw 2.0
output application/json

// SNOMED-to-ICD-10 mapping table (TS lines 47-62)
var snomedToIcd10 = {
  "44054006": { icd10: "E11.9", display: "Type 2 Diabetes Mellitus" },
  "38341003": { icd10: "I10", display: "Essential Hypertension" },
  "195967001": { icd10: "J45.909", display: "Asthma, Unspecified" },
  "431855005": { icd10: "N18.3", display: "Chronic Kidney Disease, Stage 3" },
  "370143000": { icd10: "F32.1", display: "Major Depressive Disorder" },
  "55822004": { icd10: "E78.5", display: "Hyperlipidemia" },
  "84114007": { icd10: "I50.9", display: "Heart Failure, Unspecified" },
  "13645005": { icd10: "J44.1", display: "COPD with Acute Exacerbation" },
  "233604007": { icd10: "I25.10", display: "Coronary Artery Disease" },
  "40930008": { icd10: "I48.91", display: "Atrial Fibrillation" },
  "73211009": { icd10: "E11.9", display: "Diabetes Mellitus" },
  "15777000": { icd10: "E11.65", display: "Diabetes with Hyperglycemia" },
  "46635009": { icd10: "E11.9", display: "Diabetes Mellitus Type 1" },
  "162864005": { icd10: "R73.09", display: "Prediabetes" }
}

// Extract FHIR Bundles from Scatter-Gather results
var csBundle = payload."0".payload
var mtBundle = payload."1".payload

// Normalize Flagship Hospital patients (prefix: cs-)
var csPatients = if (csBundle.entry != null)
  (csBundle.entry map (entry) -> {
    id: "cs-" ++ entry.resource.id[0 to 7],
    resourceType: "Patient",
    name: [{
      given: (entry.resource.name[0].given default ["Unknown"]),
      family: (entry.resource.name[0].family default "Unknown")
    }],
    birthDate: entry.resource.birthDate default "Unknown",
    gender: entry.resource.gender default "unknown",
    address: [{
      city: (entry.resource.address[0].city default "Unknown"),
      state: (entry.resource.address[0].state default "Unknown")
    }],
    source: "Flagship Hospital"
  })
  else []

// Normalize Community Clinic patients (prefix: mt-)
var mtPatients = if (mtBundle.entry != null)
  (mtBundle.entry map (entry) -> {
    id: "mt-" ++ entry.resource.id[0 to 7],
    resourceType: "Patient",
    name: [{
      given: (entry.resource.name[0].given default ["Unknown"]),
      family: (entry.resource.name[0].family default "Unknown")
    }],
    birthDate: entry.resource.birthDate default "Unknown",
    gender: entry.resource.gender default "unknown",
    address: [{
      city: (entry.resource.address[0].city default "Unknown"),
      state: (entry.resource.address[0].state default "Unknown")
    }],
    source: "Community Clinic"
  })
  else []
---
csPatients ++ mtPatients
]

#[output application/json --- {
              resourceType: "OperationOutcome",
              issue: [{ severity: "error", code: "not-found", diagnostics: "Unknown patient prefix. Use cs- or mt-" }]
            }]

#[output application/json --- {
            resourceType: "OperationOutcome",
            issue: [{
              severity: "error",
              code: "exception",
              diagnostics: "Clinical Federation error: " ++ (error.description default "Unknown error")
            }]
          }]
